```python
from typing import Dict

class IndexCache:
    def __init__(self):
        self.cache: Dict[str, Dict] = {}

    def get_cache(self, index_file_name: str) -> Dict:
        if index_file_name not in self.cache:
            self.cache[index_file_name] = {}
        return self.cache[index_file_name]

    def set_cache(self, index_file_name: str, key: str, value):
        self.cache[index_file_name][key] = value

    def delete_cache(self, index_file_name: str, key: str):
        if index_file_name in self.cache:
            if key in self.cache[index_file_name]:
                del self.cache[index_file_name][key]

    def clear_cache(self, index_file_name: str):
        if index_file_name in self.cache:
            self.cache[index_file_name] = {}
